initScript:
await ManagerApi.ready();
const apiBase = ManagerApi.getBase() + '/dir';
const baseDir = '/.temp';
const testDirName = 'api-dir';
return {
  apiBase, baseDir, testDirName,
  createDirUrl: apiBase + '/create_dir.php',
  scanDirUrl: apiBase + '/scan_dir.php',
  renameDirUrl: apiBase + '/rename_dir.php',
  deleteDirUrl: apiBase + '/delete_dir.php',
  message: 'init done'
};

finallyScript:
const names = ['api-dir', 'api-dir-renamed'];
for (const n of names) {
  try { await utils.postForm(deleteDirUrl, { path: baseDir + '/' + n }); } catch (_) {}
}
return { message: 'cleanup done' };

tests.scriptText:
const text = await utils.postForm(createDirUrl, { dir: baseDir, name: testDirName });
const m = text.match(/\[(.+?)\/\]/);
assert(m && m[1], 'create: parse fail');
return { dirPath: m[1], message: 'created=' + m[1] };

const text = await utils.postForm(scanDirUrl, { path: baseDir });
const arr = JSON.parse(text || '[]');
assert(Array.isArray(arr), 'scan dir: result not array');
assert(arr.includes(utils.basename(dirPath)), 'scan dir: dir missing');
return { message: 'scan ok' };

const text = await utils.postForm(renameDirUrl, { path: dirPath, name: 'api-dir-renamed' });
const m = text.match(/to \[(.+?)\/\]/);
assert(m && m[1], 'rename dir: parse fail');
const arr = JSON.parse((await utils.postForm(scanDirUrl, { path: baseDir })) || '[]');
assert(Array.isArray(arr), 'rename dir: scan result not array');
assert(!arr.includes(utils.basename(dirPath)), 'rename dir: old name still exists');
assert(arr.includes(utils.basename(m[1])), 'rename dir: new name missing');
return { renamedDirPath: m[1], message: 'renamed + verified=' + m[1] };

await utils.postForm(deleteDirUrl, { path: renamedDirPath });
const arr = JSON.parse((await utils.postForm(scanDirUrl, { path: baseDir })) || '[]');
assert(Array.isArray(arr), 'delete dir: scan result not array');
assert(!arr.includes(utils.basename(renamedDirPath)), 'delete dir: renamed still exists');
return { message: 'deleted + verified' };
